namespace sv_c763a8c2bfb74363a96e0ae869a60db2.Services;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);

public record NotificationPrefs(
    bool EmailNotifications,
    bool PushNotifications,
    bool WeeklyDigest,
    List<string> MutedChannels);

public record SecuritySettings(
    bool TwoFactorEnabled,
    DateTime? LastPasswordChange,
    List<ActiveSession> Sessions);

public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);

public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

/* ── Dashboard layout ── */
.settings-dashboard {
    display: flex;
    min-height: 70vh;
    gap: 0;
    border: 1px solid var(--bs-border-color, #dee2e6);
    border-radius: .5rem;
    overflow: hidden;
    background: var(--bs-body-bg, #fff);
}

/* ── Sidebar ── */
.settings-sidebar {
    width: 220px;
    flex-shrink: 0;
    background: var(--bs-tertiary-bg, #f8f9fa);
    border-right: 1px solid var(--bs-border-color, #dee2e6);
    padding: 1.25rem 0;
}

.sidebar-title {
    padding: 0 1.25rem .75rem;
    margin: 0;
    font-weight: 700;
    color: var(--bs-body-color);
}

.settings-sidebar .nav-link {
    display: flex;
    align-items: center;
    gap: .5rem;
    padding: .6rem 1.25rem;
    color: var(--bs-body-color, #212529);
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    font-size: .925rem;
    border-left: 3px solid transparent;
    transition: background .15s, border-color .15s;
    cursor: pointer;
}

.settings-sidebar .nav-link:hover {
    background: rgba(var(--bs-primary-rgb, 13, 110, 253), .08);
}

.settings-sidebar .nav-link.active {
    background: rgba(var(--bs-primary-rgb, 13, 110, 253), .1);
    border-left-color: var(--bs-primary, #0d6efd);
    font-weight: 600;
    color: var(--bs-primary, #0d6efd);
}

.section-icon {
    font-size: 1.1rem;
}

/* ── Content area ── */
.settings-content {
    flex: 1;
    padding: 2rem;
    min-width: 0;
}

.section-heading {
    font-weight: 700;
    margin-bottom: .25rem;
}

/* ── Avatar ── */
.avatar-preview {
    width: 120px;
    height: 120px;
    border-radius: 50%;
    overflow: hidden;
    border: 3px solid var(--bs-border-color, #dee2e6);
    display: inline-flex;
    align-items: center;
    justify-content: center;
    background: var(--bs-tertiary-bg, #f8f9fa);
}

.avatar-img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-placeholder {
    color: var(--bs-secondary-color, #6c757d);
    font-size: .8rem;
}

/* ── Preview panel ── */
.preview-area {
    border-radius: .375rem;
    padding: 1rem;
    min-height: 180px;
    transition: background .2s, color .2s;
}

.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-dark {
    background: #1e1e2e;
    color: #e0e0e0;
}

.preview-system {
    background: linear-gradient(135deg, #ffffff 50%, #1e1e2e 50%);
    color: #212529;
}

/* ── Responsive ── */
@media (max-width: 768px) {
    .settings-dashboard {
        flex-direction: column;
    }

    .settings-sidebar {
        width: 100%;
        border-right: none;
        border-bottom: 1px solid var(--bs-border-color, #dee2e6);
        padding: .75rem 0;
    }

    .settings-sidebar .nav {
        flex-direction: row !important;
        overflow-x: auto;
        gap: 0;
    }

    .settings-sidebar .nav-link {
        border-left: none;
        border-bottom: 3px solid transparent;
        white-space: nowrap;
        padding: .5rem 1rem;
    }

    .settings-sidebar .nav-link.active {
        border-left-color: transparent;
        border-bottom-color: var(--bs-primary, #0d6efd);
    }

    .settings-content {
        padding: 1rem;
    }
}

